import{_ as i,o as a,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const u=JSON.parse('{"title":"线程模型与性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/12-Netty学习/05-线程模型与性能优化.md","filePath":"语言/java/12-Netty学习/05-线程模型与性能优化.md","lastUpdated":1777177198000}'),t={name:"语言/java/12-Netty学习/05-线程模型与性能优化.md"};function s(n,l,h,p,o,d){return a(),e("div",null,[...l[0]||(l[0]=[r(`<h1 id="线程模型与性能优化" tabindex="-1">线程模型与性能优化 <a class="header-anchor" href="#线程模型与性能优化" aria-label="Permalink to “线程模型与性能优化”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>很多人学 Netty 时，一开始会把注意力放在：</p><ul><li><code>Channel</code></li><li><code>Pipeline</code></li><li>编解码</li><li>粘包拆包</li></ul><p>这些当然重要，但真正决定 Netty 能不能扛住并发、能不能跑得稳的，是它背后的：</p><ul><li><strong>线程模型</strong></li></ul><p>因为 Netty 的高性能，从来不是一句“它是非阻塞的”就解释完的。</p><p>它真正厉害的地方在于：</p><ul><li>线程怎么分工</li><li>连接和线程怎么绑定</li><li>为什么少量线程可以管理大量连接</li><li>为什么 I/O 线程不能乱塞耗时任务</li><li>为什么优化时要盯线程切换、内存分配和数据复制</li></ul><p>如果先只记一句话，可以这样记：</p><blockquote><p><strong>Netty 的线程模型核心是：让少量 EventLoop 线程高效处理大量连接上的 I/O 事件，同时尽量减少阻塞、切换和复制。</strong></p></blockquote><p>而“性能优化”说白了，就是围绕这套模型去避免把它用废。</p><hr><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>很多项目号称“用了 Netty”，但最终性能还是一般，原因并不一定是框架不行，而是：</p><ul><li>在线程模型上把它用成了阻塞程序</li><li>在 Handler 里塞了重业务</li><li>内存和对象分配过于频繁</li><li>把所有慢问题都误判成网络问题</li></ul><p>常见表现包括：</p><ul><li>连接数上来后延迟突然飙高</li><li>某个耗时接口把整个 EventLoop 拖慢</li><li>CPU 不低但吞吐就是上不去</li><li>GC 压力大</li><li>明明 I/O 不多，却有很多线程切换开销</li></ul><p>所以这一章最关键的目标不是记住术语，而是理解：</p><blockquote><p><strong>Netty 为什么能快，以及什么行为会让它突然不快。</strong></p></blockquote><hr><h2 id="_3-先建立最重要的直觉-netty-快-不代表你可以随便堵线程" tabindex="-1">3. 先建立最重要的直觉：Netty 快，不代表你可以随便堵线程 <a class="header-anchor" href="#_3-先建立最重要的直觉-netty-快-不代表你可以随便堵线程" aria-label="Permalink to “3. 先建立最重要的直觉：Netty 快，不代表你可以随便堵线程”">​</a></h2><p>Netty 的线程不是“万能线程池”。</p><p>它的优势在于：</p><ul><li>I/O 线程数量相对少</li><li>每个线程能处理很多连接的事件</li><li>同一连接通常绑定固定 EventLoop</li><li>事件分发成本低，线程切换少</li></ul><p>但这套优势有一个前提：</p><ul><li><strong>I/O 线程要尽量只做 I/O 相关的快速处理</strong></li></ul><p>如果你在 I/O 线程里直接做：</p><ul><li>慢 SQL</li><li>大量 JSON 序列化</li><li>复杂业务计算</li><li>外部 HTTP 调用</li><li>阻塞等待锁</li></ul><p>那 Netty 再优秀也会被你拖成“少量线程堵死大量连接”。</p><p>所以一开始就要建立这个核心直觉：</p><blockquote><p><strong>Netty 的性能上限，很大程度取决于你是否尊重 EventLoop 的职责边界。</strong></p></blockquote><hr><h2 id="_4-netty-的线程模型核心角色" tabindex="-1">4. Netty 的线程模型核心角色 <a class="header-anchor" href="#_4-netty-的线程模型核心角色" aria-label="Permalink to “4. Netty 的线程模型核心角色”">​</a></h2><h2 id="_4-1-boss-线程在干什么" tabindex="-1">4.1 Boss 线程在干什么 <a class="header-anchor" href="#_4-1-boss-线程在干什么" aria-label="Permalink to “4.1 Boss 线程在干什么”">​</a></h2><p>在服务端里，通常会有一组线程负责：</p><ul><li>接收新连接</li></ul><p>这组线程常被称为：</p><ul><li><code>bossGroup</code></li></ul><p>它的核心职责不是处理具体业务，而是：</p><ul><li>监听端口</li><li>接收客户端连接</li><li>把新连接注册给 worker 线程组</li></ul><p>你可以把它理解成：</p><ul><li>前台接待</li></ul><p>它负责把客户迎进门，但不负责做后续具体服务。</p><hr><h2 id="_4-2-worker-线程在干什么" tabindex="-1">4.2 Worker 线程在干什么 <a class="header-anchor" href="#_4-2-worker-线程在干什么" aria-label="Permalink to “4.2 Worker 线程在干什么”">​</a></h2><p>真正处理大部分 I/O 事件的，是：</p><ul><li><code>workerGroup</code></li></ul><p>它主要负责：</p><ul><li>读事件</li><li>写事件</li><li>执行该连接关联的 Handler 链处理</li><li>执行该 EventLoop 上的普通任务和定时任务</li></ul><p>你可以把它理解成：</p><ul><li>后台实际干活的人</li></ul><p>也就是说：</p><ul><li><code>boss</code> 负责接连接</li><li><code>worker</code> 负责管连接上的收发和事件处理</li></ul><p>这是一种非常典型的分工。</p><hr><h2 id="_5-eventloop-到底为什么关键" tabindex="-1">5. EventLoop 到底为什么关键 <a class="header-anchor" href="#_5-eventloop-到底为什么关键" aria-label="Permalink to “5. EventLoop 到底为什么关键”">​</a></h2><p><code>EventLoop</code> 是 Netty 线程模型最核心的抽象之一。</p><p>它不只是一个线程，而更像：</p><ul><li>一个“事件循环执行单元”</li></ul><p>它内部做的事情通常包括：</p><ul><li>监听 I/O 事件</li><li>分发读写事件</li><li>执行提交进来的任务</li><li>执行定时任务</li></ul><h3 id="最重要的一条规律" tabindex="-1">最重要的一条规律 <a class="header-anchor" href="#最重要的一条规律" aria-label="Permalink to “最重要的一条规律”">​</a></h3><blockquote><p><strong>一个 Channel 在生命周期内，通常绑定到一个固定的 EventLoop。</strong></p></blockquote><p>这条规律非常关键，因为它带来几个好处：</p><ul><li>同一连接上的事件通常由同一线程串行处理</li><li>大量场景下不用为每条连接额外加复杂锁</li><li>降低线程切换和竞争开销</li></ul><p>这也是为什么 Netty 很多代码写起来像“天然线程安全一些”——前提是你没有主动把问题搞复杂。</p><hr><h2 id="_6-为什么说同一连接固定线程处理是性能优势" tabindex="-1">6. 为什么说同一连接固定线程处理是性能优势 <a class="header-anchor" href="#_6-为什么说同一连接固定线程处理是性能优势" aria-label="Permalink to “6. 为什么说同一连接固定线程处理是性能优势”">​</a></h2><p>你可以想象两种方案。</p><h3 id="方案-a-同一连接今天给线程-1-明天给线程-7-后天给线程-3" tabindex="-1">方案 A：同一连接今天给线程 1，明天给线程 7，后天给线程 3 <a class="header-anchor" href="#方案-a-同一连接今天给线程-1-明天给线程-7-后天给线程-3" aria-label="Permalink to “方案 A：同一连接今天给线程 1，明天给线程 7，后天给线程 3”">​</a></h3><p>会带来：</p><ul><li>上下文切换多</li><li>线程竞争多</li><li>状态同步麻烦</li><li>更容易出现并发问题</li></ul><h3 id="方案-b-同一连接一直由固定线程处理" tabindex="-1">方案 B：同一连接一直由固定线程处理 <a class="header-anchor" href="#方案-b-同一连接一直由固定线程处理" aria-label="Permalink to “方案 B：同一连接一直由固定线程处理”">​</a></h3><p>会带来：</p><ul><li>事件顺序更自然</li><li>减少共享状态同步</li><li>更少锁竞争</li><li>CPU cache 友好度通常更高</li></ul><p>Netty 更偏向方案 B。</p><p>这并不意味着“绝对不用考虑线程安全”，而是意味着：</p><ul><li><strong>连接内串行处理这件事，已经帮你减少了一大类并发复杂度。</strong></li></ul><hr><h2 id="_7-为什么-i-o-线程不适合执行重业务" tabindex="-1">7. 为什么 I/O 线程不适合执行重业务 <a class="header-anchor" href="#_7-为什么-i-o-线程不适合执行重业务" aria-label="Permalink to “7. 为什么 I/O 线程不适合执行重业务”">​</a></h2><p>这是面试和实战里都极其高频的点。</p><p>假设一个 <code>EventLoop</code> 正在负责 2000 个连接。</p><p>如果其中某个请求在 <code>channelRead</code> 里直接执行一个耗时 2 秒的数据库查询，会发生什么？</p><p>答案是：</p><ul><li>这 2 秒里，这个 EventLoop 上其他连接的事件处理也会被拖慢</li></ul><p>因为它们共享同一个事件循环线程。</p><p>结果你可能看到：</p><ul><li>某一个慢请求影响一批连接</li><li>心跳超时</li><li>写回延迟增加</li><li>整体吞吐下降</li></ul><p>所以要牢记一句话：</p><blockquote><p><strong>I/O 线程最怕“被长时间占住”。</strong></p></blockquote><p>I/O 线程更适合做的是：</p><ul><li>快速解码</li><li>基础校验</li><li>轻量路由</li><li>投递任务到业务线程池</li><li>快速写回</li></ul><p>而不是：</p><ul><li>重计算</li><li>阻塞数据库操作</li><li>长时间外部 RPC</li><li>大文件慢处理</li></ul><hr><h2 id="_8-正确做法-i-o-和业务线程分离" tabindex="-1">8. 正确做法：I/O 和业务线程分离 <a class="header-anchor" href="#_8-正确做法-i-o-和业务线程分离" aria-label="Permalink to “8. 正确做法：I/O 和业务线程分离”">​</a></h2><p>更合理的工程做法通常是：</p><ol><li>I/O 线程负责网络层快速处理</li><li>耗时业务投递到专门业务线程池</li><li>业务处理完后，再把结果写回连接</li></ol><p>例如思路上可以这样：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Override</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> channelRead</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ChannelHandlerContext ctx, Object msg) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bizExecutor.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">submit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Object response </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> doHeavyBusiness</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(msg);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ctx.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writeAndFlush</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(response);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>当然，真实项目里你还要继续考虑：</p><ul><li>业务线程池大小</li><li>队列是否会堆积</li><li>超时与拒绝策略</li><li>回写线程安全与顺序性</li></ul><p>但最基本的原则已经出来了：</p><ul><li><strong>不要让重业务长期占住 EventLoop。</strong></li></ul><hr><h2 id="_9-线程模型之外-性能到底在优化什么" tabindex="-1">9. 线程模型之外，性能到底在优化什么 <a class="header-anchor" href="#_9-线程模型之外-性能到底在优化什么" aria-label="Permalink to “9. 线程模型之外，性能到底在优化什么”">​</a></h2><p>Netty 的性能优化并不是一个点，而是一组方向。</p><p>通常主要围绕这几类：</p><ul><li>减少线程切换</li><li>减少阻塞等待</li><li>减少内存复制</li><li>减少频繁分配回收</li><li>减少无意义的对象创建</li><li>减少无边界的写入堆积</li></ul><p>所以别把“性能优化”简单理解成调两个参数。</p><p>更准确地说，它是：</p><ul><li><strong>在系统路径上减少浪费</strong></li></ul><hr><h2 id="_10-零拷贝到底在说什么" tabindex="-1">10. 零拷贝到底在说什么 <a class="header-anchor" href="#_10-零拷贝到底在说什么" aria-label="Permalink to “10. 零拷贝到底在说什么”">​</a></h2><p>“零拷贝”这个词很容易被神化。</p><p>你入门阶段先不用追底层所有实现细节，只要先理解它想优化的核心矛盾：</p><ul><li>数据在传输过程中，复制越多，CPU 和内存带宽浪费越大</li></ul><p>所以 Netty 会尽量通过一些方式：</p><ul><li>减少不必要的数据复制</li><li>提高 I/O 传输效率</li></ul><p>例如常见认知点包括：</p><ul><li>使用直接内存</li><li>复合缓冲区</li><li>文件传输优化</li></ul><p>你可以先把它理解成：</p><ul><li><strong>少搬一次数据，就可能少一笔成本。</strong></li></ul><p>这类优化在高吞吐场景里很有价值。</p><hr><h2 id="_11-内存池与对象复用为什么重要" tabindex="-1">11. 内存池与对象复用为什么重要 <a class="header-anchor" href="#_11-内存池与对象复用为什么重要" aria-label="Permalink to “11. 内存池与对象复用为什么重要”">​</a></h2><p>高并发网络程序里，如果你每次收发消息都：</p><ul><li>新建很多对象</li><li>频繁申请释放缓冲区</li></ul><p>就容易带来：</p><ul><li>GC 压力</li><li>延迟抖动</li><li>CPU 浪费</li></ul><p>Netty 之所以强调 <code>ByteBuf</code>、池化、引用计数，本质上就是在优化：</p><ul><li>内存分配成本</li><li>对象生命周期管理</li></ul><h3 id="通俗理解" tabindex="-1">通俗理解 <a class="header-anchor" href="#通俗理解" aria-label="Permalink to “通俗理解”">​</a></h3><p>不要把它想成“高级技巧”，而要把它看成：</p><ul><li>高并发场景里，频繁创建和销毁本身就是性能问题</li></ul><p>所以对象复用、缓冲区池化，本质上都是在减少系统开销。</p><hr><h2 id="_12-一个很常见的错误链路" tabindex="-1">12. 一个很常见的错误链路 <a class="header-anchor" href="#_12-一个很常见的错误链路" aria-label="Permalink to “12. 一个很常见的错误链路”">​</a></h2><p>很多性能问题其实都可以还原成这样一条错误链：</p><ol><li>在 <code>channelRead</code> 里直接做慢业务</li><li>EventLoop 被卡住</li><li>该线程负责的其他连接也变慢</li><li>心跳延迟、写回堆积、超时变多</li><li>上层开始重试</li><li>系统进一步放大压力</li></ol><p>所以很多人最后说“Netty 顶不住”，其实真实原因是：</p><ul><li>线程职责被破坏后，局部慢请求放大成了全局抖动</li></ul><hr><h2 id="_13-优化时一般先看什么" tabindex="-1">13. 优化时一般先看什么 <a class="header-anchor" href="#_13-优化时一般先看什么" aria-label="Permalink to “13. 优化时一般先看什么”">​</a></h2><p>别一上来就改参数，先看现象对应哪一层。</p><h3 id="_13-1-看-eventloop-有没有被堵" tabindex="-1">13.1 看 EventLoop 有没有被堵 <a class="header-anchor" href="#_13-1-看-eventloop-有没有被堵" aria-label="Permalink to “13.1 看 EventLoop 有没有被堵”">​</a></h3><p>关注：</p><ul><li>某些连接是否明显延迟高</li><li>是否有耗时 Handler</li><li>是否存在阻塞调用</li></ul><h3 id="_13-2-看线程池是否堆积" tabindex="-1">13.2 看线程池是否堆积 <a class="header-anchor" href="#_13-2-看线程池是否堆积" aria-label="Permalink to “13.2 看线程池是否堆积”">​</a></h3><p>关注：</p><ul><li>业务线程池队列长度</li><li>拒绝次数</li><li>平均处理耗时</li></ul><h3 id="_13-3-看内存和-gc" tabindex="-1">13.3 看内存和 GC <a class="header-anchor" href="#_13-3-看内存和-gc" aria-label="Permalink to “13.3 看内存和 GC”">​</a></h3><p>关注：</p><ul><li>是否对象创建过于频繁</li><li>是否缓冲区使用不合理</li><li>是否出现内存泄漏或直接内存压力</li></ul><h3 id="_13-4-看写出是否有背压" tabindex="-1">13.4 看写出是否有背压 <a class="header-anchor" href="#_13-4-看写出是否有背压" aria-label="Permalink to “13.4 看写出是否有背压”">​</a></h3><p>关注：</p><ul><li>写缓冲区是否堆积</li><li>下游读取是否过慢</li><li>是否一直无边界写入</li></ul><p>这说明 Netty 性能排查从来不是只看“QPS 不高”。</p><p>而是要看：</p><ul><li>线程</li><li>队列</li><li>内存</li><li>I/O</li><li>下游依赖</li></ul><p>一起分析。</p><hr><h2 id="_14-动手建议" tabindex="-1">14. 动手建议 <a class="header-anchor" href="#_14-动手建议" aria-label="Permalink to “14. 动手建议”">​</a></h2><p>建议你至少做 3 个实验。</p><h3 id="_14-1-故意在-handler-里-thread-sleep" tabindex="-1">14.1 故意在 Handler 里 <code>Thread.sleep</code> <a class="header-anchor" href="#_14-1-故意在-handler-里-thread-sleep" aria-label="Permalink to “14.1 故意在 Handler 里 Thread.sleep”">​</a></h3><p>目标：</p><ul><li>直观看到 EventLoop 被阻塞后的影响</li></ul><h3 id="_14-2-把耗时逻辑迁到业务线程池" tabindex="-1">14.2 把耗时逻辑迁到业务线程池 <a class="header-anchor" href="#_14-2-把耗时逻辑迁到业务线程池" aria-label="Permalink to “14.2 把耗时逻辑迁到业务线程池”">​</a></h3><p>目标：</p><ul><li>对比处理延迟变化</li></ul><h3 id="_14-3-观察对象创建和-gc-压力" tabindex="-1">14.3 观察对象创建和 GC 压力 <a class="header-anchor" href="#_14-3-观察对象创建和-gc-压力" aria-label="Permalink to “14.3 观察对象创建和 GC 压力”">​</a></h3><p>目标：</p><ul><li>理解“看起来只是 new 了几个对象”为什么在线上会被放大</li></ul><hr><h2 id="_15-最容易踩的坑" tabindex="-1">15. 最容易踩的坑 <a class="header-anchor" href="#_15-最容易踩的坑" aria-label="Permalink to “15. 最容易踩的坑”">​</a></h2><h3 id="_15-1-在-i-o-线程中执行耗时任务" tabindex="-1">15.1 在 I/O 线程中执行耗时任务 <a class="header-anchor" href="#_15-1-在-i-o-线程中执行耗时任务" aria-label="Permalink to “15.1 在 I/O 线程中执行耗时任务”">​</a></h3><p>这是最常见、也是破坏性最大的坑。</p><h3 id="_15-2-误以为线程越多越好" tabindex="-1">15.2 误以为线程越多越好 <a class="header-anchor" href="#_15-2-误以为线程越多越好" aria-label="Permalink to “15.2 误以为线程越多越好”">​</a></h3><p>线程不是越多越快，盲目加线程可能带来：</p><ul><li>更多切换成本</li><li>更多调度开销</li><li>更多竞争</li></ul><h3 id="_15-3-只盯网络-不盯业务阻塞" tabindex="-1">15.3 只盯网络，不盯业务阻塞 <a class="header-anchor" href="#_15-3-只盯网络-不盯业务阻塞" aria-label="Permalink to “15.3 只盯网络，不盯业务阻塞”">​</a></h3><p>很多慢问题根本不是网络层本身，而是业务把 EventLoop 拖慢了。</p><h3 id="_15-4-忽视内存池、对象复用和直接内存" tabindex="-1">15.4 忽视内存池、对象复用和直接内存 <a class="header-anchor" href="#_15-4-忽视内存池、对象复用和直接内存" aria-label="Permalink to “15.4 忽视内存池、对象复用和直接内存”">​</a></h3><p>这会让高并发下的 GC 和复制成本明显上升。</p><h3 id="_15-5-把所有性能问题都归因于框架" tabindex="-1">15.5 把所有性能问题都归因于框架 <a class="header-anchor" href="#_15-5-把所有性能问题都归因于框架" aria-label="Permalink to “15.5 把所有性能问题都归因于框架”">​</a></h3><p>Netty 通常只是承载问题暴露的地方，不一定是问题来源本身。</p><hr><h2 id="_16-自测问题" tabindex="-1">16. 自测问题 <a class="header-anchor" href="#_16-自测问题" aria-label="Permalink to “16. 自测问题”">​</a></h2><ul><li>为什么一个 <code>Channel</code> 通常绑定固定 <code>EventLoop</code> 是性能优势？</li><li>为什么 I/O 线程不适合执行重业务？</li><li><code>bossGroup</code> 和 <code>workerGroup</code> 各自承担什么职责？</li><li>Netty 的性能优化为什么经常和“减少线程切换、减少复制、减少分配”有关？</li><li>排查 Netty 性能问题时，为什么不能只盯着网络层？</li></ul><hr><h2 id="_17-这一章你至少要带走什么" tabindex="-1">17. 这一章你至少要带走什么 <a class="header-anchor" href="#_17-这一章你至少要带走什么" aria-label="Permalink to “17. 这一章你至少要带走什么”">​</a></h2><p>如果你看完这一章只记住 5 件事，就记下面这 5 件：</p><ol><li><strong>Netty 的核心性能基础，是 EventLoop 驱动的大量连接管理模型</strong></li><li><strong>一个 Channel 通常绑定固定 EventLoop，有助于减少竞争和切换</strong></li><li><strong>I/O 线程要尽量轻，不要长时间被重业务占住</strong></li><li><strong>性能优化常常来自减少阻塞、切换、复制和频繁分配</strong></li><li><strong>Netty 慢，很多时候不是框架慢，而是线程职责和资源使用方式出了问题</strong></li></ol><p>把这几个点真正建立起来后，你对 Netty 的理解才会从“会用 API”进入“能解释为什么快、为什么会慢”的阶段。</p>`,195)])])}const k=i(t,[["render",s]]);export{u as __pageData,k as default};
